// === FORJA · Validar JSON de la IA y armar el correo ===
const raw = ($json.text || '').toString();
const clean = raw.replace(/```json/gi, '').replace(/```/g, '').trim();

let data;
try {
  data = JSON.parse(clean);
} catch (e) {
  throw new Error('La IA no devolvió un JSON válido: ' + e.message);
}

// Guardrail: validar estructura mínima
if (!data.dias || !Array.isArray(data.dias) || data.dias.length === 0) {
  throw new Error('El JSON no contiene un arreglo de días válido');
}

// Datos del formulario (nodo trigger)
const trigger = $('Nueva fila en Sheet').item.json;
const nombre = trigger.Nombre || 'crack';
const email = trigger.Email;

// Construir el HTML de los días
let diasHtml = '';
for (const dia of data.dias) {
  diasHtml += '<h3 style=\'color:#2E9E6D;margin:22px 0 8px;font-size:17px;\'>' + (dia.titulo || 'Día') + '</h3>';
  diasHtml += '<ul style=\'margin:0 0 4px;padding-left:20px;color:#333;font-size:15px;line-height:1.6;\'>';
  for (const ej of (dia.ejercicios || [])) {
    const nota = ej.nota ? ' <em style=\'color:#777;\'>(' + ej.nota + ')</em>' : '';
    diasHtml += '<li style=\'margin-bottom:5px;\'><strong>' + ej.ejercicio + '</strong> — ' + ej.series + ' series × ' + ej.reps + ' reps' + nota + '</li>';
  }
  diasHtml += '</ul>';
}

const saludo = data.saludo || ('¡Hola ' + nombre + '!');
const resumen = data.resumen || '';
const consejo = data.consejo || '¡A darlo todo!';

const html =
'<div style=\'font-family:Arial,sans-serif;background-color:#f7f9fa;padding:30px;\'>' +
  '<div style=\'max-width:600px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 4px 10px rgba(0,0,0,0.05);\'>' +
    '<div style=\'background:#2E9E6D;color:#fff;padding:30px 20px;text-align:center;\'>' +
      '<h1 style=\'margin:0;font-size:24px;\'>¡Tu rutina está lista! 🏋️</h1>' +
    '</div>' +
    '<div style=\'padding:30px;\'>' +
      '<p style=\'font-size:16px;color:#333;margin-top:0;\'>' + saludo + '</p>' +
      '<p style=\'font-size:15px;color:#333;line-height:1.5;\'>' + resumen + '</p>' +
      diasHtml +
      '<p style=\'font-size:15px;color:#333;margin-top:22px;\'>' + consejo + '</p>' +
    '</div>' +
    '<div style=\'padding:20px;text-align:center;color:#888;font-size:14px;border-top:1px solid #eee;\'>' +
      'Con cariño,<br><strong>Equipo Forja Rutinas 💪</strong>' +
    '</div>' +
  '</div>' +
'</div>';

return { json: { email: email, nombre: nombre, html: html } };
